#include <stdio.h>
#include <limits.h>

int main() {
    int N;
    scanf("%d", &N);
    int T[N];
    for (int i = 0; i < N; i++) {
        scanf("%d", &T[i]);
    }
    int min_temp = INT_MAX, max_temp = INT_MIN;
    for (int i = 0; i < N; i++) {
        if (T[i] < min_temp) min_temp = T[i];
        if (T[i] > max_temp) max_temp = T[i];
    }
    int start = -1, end = -1;
    for (int i = 0; i < N; i++) {
        if (T[i] == min_temp) start = i;
        if (T[i] == max_temp) end = i;
    }
    if (start == -1 || end == -1 || start == end) {
        printf("-1\n");
        return 0;
    }
    int path_length = 0;
    for (int i = start; i != end; ) {
        if (i < end && T[i + 1] > T[i]) {
            i++;
        } else if (i > end && T[i - 1] < T[i]) {
            i--;
        } else {
            printf("-1\n");
            return 0;
        }
        path_length++;
    }
    printf("%d\n", path_length + 1);
    return 0;
}

