using namespace std;

int main() {
    int N;
    cin >> N;
    vector<int> temperatures(N);
    for (int i = 0; i < N; ++i) {
        cin >> temperatures[i];
    }

    vector<int> dist(N, numeric_limits<int>::max());
    dist[0] = 0;
    queue<int> q;
    q.push(0);

    while (!q.empty()) {
        int current = q.front();
        q.pop();

        for (int next = current + 1; next < N; ++next) {
            if (temperatures[next] > temperatures[current] && dist[next] > dist[current] + 1) {
                dist[next] = dist[current] + 1;
                q.push(next);
            }
        }
    }

    if (dist[N - 1] == numeric_limits<int>::max()) {
        cout << -1 << endl;
    } else {
        cout << dist[N - 1] << endl;
    }
    return 0;
}

import java.util.*;

public class Main {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int N = scanner.nextInt();
        int[] temperatures = new int[N];
        for (int i = 0; i < N; i++) {
            temperatures[i] = scanner.nextInt();
        }

        int minTempIndex = 0;
        int maxTempIndex = 0;
        for (int i = 1; i < N; i++) {
            if (temperatures[i] < temperatures[minTempIndex]) {
                minTempIndex = i;
            }
            if (temperatures[i] > temperatures[maxTempIndex]) {
                maxTempIndex = i;
            }
        }

        if (minTempIndex == maxTempIndex) {
            System.out.println(1);
            return;
        }

        Queue<Integer> queue = new LinkedList<>();
        boolean[] visited = new boolean[N];
        int[] distance = new int[N];
        Arrays.fill(distance, -1);

        queue.add(minTempIndex);
        visited[minTempIndex] = true;
        distance[minTempIndex] = 1;

        while (!queue.isEmpty()) {
            int currentIndex = queue.poll();
            for (int nextIndex = currentIndex + 1; nextIndex < N; nextIndex++) {
                if (temperatures[nextIndex] > temperatures[currentIndex] && !visited[nextIndex]) {
                    visited[nextIndex] = true;
                    distance[nextIndex] = distance[currentIndex] + 1;
                    queue.add(nextIndex);
                    if (nextIndex == maxTempIndex) {
                        System.out.println(distance[nextIndex]);
                        return;
                    }
                }
            }
        }

        System.out.println(-1);
    }
}

