int main() {
    int N, M;
    scanf("%d %d", &N, &M);
    int *indegree = (int *)calloc(N + 1, sizeof(int));
    int **graph = (int **)malloc((N + 1) * sizeof(int *));
    for (int i = 0; i <= N; i++) graph[i] = (int *)malloc((N + 1) * sizeof(int));

    for (int i = 0; i < M; i++) {
        int A, B;
        scanf("%d %d", &A, &B);
        graph[A][indegree[A]] = B;
        indegree[B]++;
    }

    int *queue = (int *)malloc((N + 1) * sizeof(int));
    int front = 0, rear = 0;
    for (int i = 1; i <= N; i++) {
        if (indegree[i] == 0) {
            queue[rear++] = i;
        }
    }

    int count = 0;
    while (front < rear) {
        int node = queue[front++];
        count++;
        for (int j = 0; j < N; j++) {
            if (graph[node][j] != 0) {
                int neighbor = graph[node][j];
                indegree[neighbor]--;
                if (indegree[neighbor] == 0) {
                    queue[rear++] = neighbor;
                }
            }
        }
    }

    if (count == N) {
        printf("YES\n");
    } else {
        printf("NO\n");
    }

    free(indegree);
    free(queue);
    for (int i = 0; i <= N; i++) free(graph[i]);
    free(graph);
    return 0;
}

