    scanf("%d", &N);
    int id[10];
    char priority[10][10];
    int count = 0;

    for (int i = 0; i < N; i++) {
        int patient_id;
        char patient_priority[10];
        scanf("%d %s", &patient_id, patient_priority);
        if (count < 10) {
            id[count] = patient_id;
            strcpy(priority[count], patient_priority);
            count++;
        } else {
            printf("キューが満杯です。\n");
        }
    }

    printf("処理された患者:\n");
    for (int i = 0; i < count; i++) {
        for (int j = i + 1; j < count; j++) {
            if (strcmp(priority[i], "emergency") == 0 && strcmp(priority[j], "normal") == 0) {
                int temp_id = id[i];
                id[i] = id[j];
                id[j] = temp_id;
                char temp_priority[10];
                strcpy(temp_priority, priority[i]);
                strcpy(priority[i], priority[j]);
                strcpy(priority[j], temp_priority);
            }
        }
    }

    for (int i = 0; i < count; i++) {
        printf("%d\n", id[i]);
        for (int j = 0; j < count; j++) {
            if (id[i] == id[j]) {
                for (int k = j; k < count - 1; k++) {
                    id[k] = id[k + 1];
                    strcpy(priority[k], priority[k + 1]);
                }
                count--;
                break;
            }
        }
    }

    printf("現在のキューの状態:\n");
    for (int i = 0; i < count; i++) {
        printf("(%d %s)\n", id[i], priority[i]);
    }

    return 0;
}

