public class HospitalQueue {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int N = scanner.nextInt();
        PriorityQueue<Patient> queue = new PriorityQueue<>((a, b) -> {
            if (a.priority.equals(b.priority)) {
                return Integer.compare(a.id, b.id);
            }
            return a.priority.equals("emergency") ? -1 : 1;
        });
        for (int i = 0; i < N; i++) {
            int id = scanner.nextInt();
            String priority = scanner.next();
            if (queue.size() < 10) {
                queue.add(new Patient(id, priority));
            } else {
                System.out.println("エラー: キューが満杯です");
            }
        }
        System.out.println("処理された患者:");
        while (!queue.isEmpty()) {
            Patient patient = queue.poll();
            System.out.println(patient.id);
        }
        System.out.println("現在のキューの状態:");
        if (queue.isEmpty()) {
            System.out.println("空です");
        } else {
            for (Patient patient : queue) {
                System.out.printf("(%d %s) ", patient.id, patient.priority);
            }
        }
    }

    static class Patient {
        int id;
        String priority;
        Patient(int id, String priority) {
            this.id = id;
            this.priority = priority;
        }
    }
}

