#include <stdio.h>
#include <stdlib.h>
#include <string.h>

int main() {
    int N, M;
    scanf("%d %d", &N, &M);
    int *queue = (int *)malloc(N * sizeof(int));
    int size = 0;

    for (int i = 0; i < M; i++) {
        char command[10];
        scanf("%s", command);
        if (strcmp(command, "enqueue") == 0) {
            int priority;
            scanf("%d", &priority);
            if (size < N) {
                queue[size++] = priority;
                // Sort the queue in descending order
                for (int j = size - 1; j > 0 && queue[j] > queue[j - 1]; j--) {
                    int temp = queue[j];
                    queue[j] = queue[j - 1];
                    queue[j - 1] = temp;
                }
            }
        } else if (strcmp(command, "dequeue") == 0) {
            if (size > 0) {
                size--;
            }
        } else if (strcmp(command, "status") == 0) {
            if (size == 0) {
                printf("empty\n");
            } else {
                for (int j = 0; j < size; j++) {
                    printf("%d\n", queue[j]);
                }
            }
        }
    }

    free(queue);
    return 0;
}

