int main() {
    int N, M;
    std::cin >> N >> M;
    std::priority_queue<int> pq;
    std::string command;
    for (int i = 0; i < M; ++i) {
        std::cin >> command;
        if (command == "enqueue") {
            int x;
            std::cin >> x;
            if (pq.size() < N) {
                pq.push(x);
            }
        } else if (command == "dequeue") {
            if (!pq.empty()) {
                pq.pop();
            }
        } else if (command == "status") {
            if (pq.empty()) {
                std::cout << "empty" << std::endl;
            } else {
                std::vector<int> temp;
                while (!pq.empty()) {
                    temp.push_back(pq.top());
                    pq.pop();
                }
                for (int j = 0; j < temp.size(); ++j) {
                    std::cout << temp[j];
                    if (j != temp.size() - 1) std::cout << std::endl;
                }
                for (int j = temp.size() - 1; j >= 0; --j) {
                    pq.push(temp[j]);
                }
            }
        }
    }
    return 0;
}

