#include <stdio.h>
#include <stdlib.h>
#include <math.h>

int compare(const void *a, const void *b) {
    return (*(int *)a - *(int *)b);
}

int main() {
    int N;
    scanf("%d", &N);
    int *scores = (int *)malloc(N * sizeof(int));
    for (int i = 0; i < N; i++) {
        scanf("%d", &scores[i]);
    }

    // Sort the scores using quicksort
    qsort(scores, N, sizeof(int), compare);

    // Calculate mean and standard deviation
    double sum = 0.0, mean, stddev = 0.0;
    for (int i = 0; i < N; i++) {
        sum += scores[i];
    }
    mean = sum / N;

    for (int i = 0; i < N; i++) {
        stddev += (scores[i] - mean) * (scores[i] - mean);
    }
    stddev = sqrt(stddev / N);

    double lower_bound = mean - 2 * stddev;
    double upper_bound = mean + 2 * stddev;

    // Collect outliers
    int *outliers = (int *)malloc(N * sizeof(int));
    int outlier_count = 0;
    for (int i = 0; i < N; i++) {
        if (scores[i] < lower_bound || scores[i] > upper_bound) {
            outliers[outlier_count++] = scores[i];
        }
    }

    // Sort outliers
    qsort(outliers, outlier_count, sizeof(int), compare);

    // Output outliers
    for (int i = 0; i < outlier_count; i++) {
        printf("%d\n", outliers[i]);
    }
    if (outlier_count == 0) {
        printf("\n");
    }

    free(scores);
    free(outliers);
    return 0;
}

#include <iostream>
