#include <algorithm>
#include <cmath>

int main() {
    int N;
    std::cin >> N;
    std::vector<int> scores(N);
    for (int i = 0; i < N; ++i) {
        std::cin >> scores[i];
    }

    double sum = 0.0;
    for (int score : scores) {
        sum += score;
    }
    double mean = sum / N;

    double variance = 0.0;
    for (int score : scores) {
        variance += (score - mean) * (score - mean);
    }
    variance /= N;
    double stddev = std::sqrt(variance);

    double lower_bound = mean - 2 * stddev;
    double upper_bound = mean + 2 * stddev;

    std::vector<int> outliers;
    for (int score : scores) {
        if (score < lower_bound || score > upper_bound) {
            outliers.push_back(score);
        }
    }

    std::sort(outliers.begin(), outliers.end());

    for (int outlier : outliers) {
        std::cout << outlier << '\n';
    }
    return 0;
}

import java.util.*;

public class Main {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int N = scanner.nextInt();
        int[] scores = new int[N];
        for (int i = 0; i < N; i++) {
            scores[i] = scanner.nextInt();
        }
        Arrays.sort(scores);

        double mean = Arrays.stream(scores).average().orElse(0.0);
        double stddev = Math.sqrt(Arrays.stream(scores).mapToDouble(x -> Math.pow(x - mean, 2)).average().orElse(0.0));
        double lowerBound = mean - 2 * stddev;
        double upperBound = mean + 2 * stddev;

        List<Integer> outliers = new ArrayList<>();
        for (int score : scores) {
            if (score < lowerBound || score > upperBound) {
                outliers.add(score);
            }
        }

        if (outliers.isEmpty()) {
            System.out.println("[]");
        } else {
            Collections.sort(outliers);
            System.out.println(outliers);
        }
    }
}

