typedef struct {
    char name[100];
    int stock;
    int sales;
} Product;

int compare(const void *a, const void *b) {
    Product *p1 = (Product *)a;
    Product *p2 = (Product *)b;
    if (p1->stock != p2->stock) {
        return p1->stock - p2->stock;
    }
    return p2->sales - p1->sales;
}

int main() {
    int M, N;
    scanf("%d %d", &M, &N);
    Product products[M];

    for (int i = 0; i < M; i++) {
        char stockStr[20], salesStr[20];
        scanf("%s %s %s", products[i].name, stockStr, salesStr);
        products[i].stock = atoi(stockStr);
        products[i].sales = atoi(salesStr);
    }

    qsort(products, M, sizeof(Product), compare);

    for (int i = 0; i < N; i++) {
        printf("%s\t%d\n", products[i].name, products[i].stock);
    }
    return 0;
}

