int main() {
    char schedule[100][20];
    int count = 0;
    char command[20];
    while (1) {
        fgets(command, sizeof(command), stdin);
        if (strncmp(command, "追加", 6) == 0) {
            char start[10], end[10];
            sscanf(command + 6, "%s %s", start, end);
            int conflict = 0;
            for (int i = 0; i < count; i++) {
                char existing_start[10], existing_end[10];
                sscanf(schedule[i], "%s %s", existing_start, existing_end);
                if ((strcmp(start, existing_end) < 0 && strcmp(end, existing_start) > 0)) {
                    conflict = 1;
                    break;
                }
            }
            if (conflict) {
                printf("予定が重複しています\n");
            } else {
                strcpy(schedule[count], command + 6);
                count++;
            }
        } else {
            strcpy(schedule[count], command);
            count++;
        }
        // Sort the schedule
        for (int i = 0; i < count - 1; i++) {
            for (int j = i + 1; j < count; j++) {
                if (strcmp(schedule[i], schedule[j]) > 0) {
                    char temp[20];
                    strcpy(temp, schedule[i]);
                    strcpy(schedule[i], schedule[j]);
                    strcpy(schedule[j], temp);
                }
            }
        }
