using namespace std;

struct Schedule {
    string start;
    string end;
};

bool isOverlapping(const Schedule &newSchedule, const vector<Schedule> &schedules) {
    for (const auto &schedule : schedules) {
        if ((newSchedule.start < schedule.end) && (newSchedule.end > schedule.start)) {
            return true;
        }
    }
    return false;
}

int main() {
    vector<Schedule> schedules;
    string input;
    while (getline(cin, input)) {
        stringstream ss(input);
        string command;
        ss >> command;

        if (command == "追加") {
            Schedule newSchedule;
            ss >> newSchedule.start >> newSchedule.end;
            if (isOverlapping(newSchedule, schedules)) {
                cout << "予定が重複しています" << endl;
            } else {
                schedules.push_back(newSchedule);
            }
        } else {
            Schedule schedule;
            schedule.start = input.substr(0, 5);
            schedule.end = input.substr(6, 5);
            schedules.push_back(schedule);
        }
    }

    sort(schedules.begin(), schedules.end(), [](const Schedule &a, const Schedule &b) {
        return a.start < b.start;
    });

    for (const auto &schedule : schedules) {
        cout << schedule.start << " " << schedule.end << endl;
    }

    return 0;
}

