public class Main {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        List<String[]> schedule = new ArrayList<>();
        while (scanner.hasNextLine()) {
            String line = scanner.nextLine();
            String[] parts = line.split(" ");
            if (parts[0].equals("追加")) {
                String startTime = parts[1];
                String endTime = parts[2];
                if (isTimeOverlap(schedule, startTime, endTime)) {
                    System.out.println("予定が重複しています");
                } else {
                    schedule.add(new String[]{startTime, endTime});
                }
            } else {
                schedule.add(parts);
            }
        }
        Collections.sort(schedule, Comparator.comparing(a -> a[0]));
        for (String[] entry : schedule) {
            System.out.println(entry[0] + " " + entry[1]);
        }
    }

    private static boolean isTimeOverlap(List<String[]> schedule, String startTime, String endTime) {
        for (String[] entry : schedule) {
            if (isOverlapping(entry[0], entry[1], startTime, endTime)) {
                return true;
            }
        }
        return false;
    }

    private static boolean isOverlapping(String start1, String end1, String start2, String end2) {
        return (start1.compareTo(end2) < 0 && start2.compareTo(end1) < 0);
    }
}

