#include <stdio.h>
#include <string.h>
#include <stdlib.h>
#include <ctype.h>

#define MAX_POSTS 1000
#define MAX_LENGTH 101

typedef struct {
    char post[MAX_LENGTH];
    int count;
} Post;

int compare(const void *a, const void *b) {
    Post *postA = (Post *)a;
    Post *postB = (Post *)b;
    if (postB->count != postA->count) {
        return postB->count - postA->count;
    }
    return strcmp(postA->post, postB->post);
}

int main() {
    int N;
    scanf("%d", &N);
    Post posts[MAX_POSTS];
    int total_posts = 0;
    char input[MAX_LENGTH];

    for (int i = 0; i < N; i++) {
        scanf("%s", input);
        // To handle the case-insensitivity
        char temp[MAX_LENGTH];
        strcpy(temp, input);
        for (int j = 0; temp[j]; j++) {
            temp[j] = tolower(temp[j]);
        }

        int found = 0;
        for (int j = 0; j < total_posts; j++) {
            if (strcmp(temp, posts[j].post) == 0) {
                posts[j].count++;
                found = 1;
                break;
            }
        }

        if (!found) {
            strcpy(posts[total_posts].post, input);
            posts[total_posts].count = 1;
            total_posts++;
        }
    }

    qsort(posts, total_posts, sizeof(Post), compare);

    for (int i = 0; i < total_posts; i++) {
        printf("%s %d\n", posts[i].post, posts[i].count);
    }

    return 0;
}

