int main() {
    int N;
    scanf("%d", &N);
    int hp[N];
    for (int i = 0; i < N; i++) {
        scanf("%d", &hp[i]);
    }
    // Selection sort
    for (int i = 0; i < N - 1; i++) {
        int min_index = i;
        for (int j = i + 1; j < N; j++) {
            if (hp[j] < hp[min_index]) {
                min_index = j;
            }
        }
        // Swap
        int temp = hp[i];
        hp[i] = hp[min_index];
        hp[min_index] = temp;
    }
    for (int i = 0; i < N; i++) {
        printf("%d", hp[i]);
        if (i < N - 1) printf(" ");
    }
    printf("\n");
    return 0;
}

