        // 2. Calculate difference between max and min temperatures
        int max = Arrays.stream(temperatures).max().getAsInt();
        int min = Arrays.stream(temperatures).min().getAsInt();
        int difference = max - min;
        System.out.println(difference);

        // 3. Reverse the temperature array and get the first 3 days
        int[] reversed = new int[7];
        for (int i = 0; i < 7; i++) {
            reversed[i] = temperatures[6 - i];
        }
        System.out.println(reversed[0] + " " + reversed[1] + " " + reversed[2]);
    }
}

