def sum_of_prime_divisors(*args):
    if not args:
        args = (10,)
    prime_sums = []
    for n in args:
        divisors = [i for i in range(1, n + 1) if n % i == 0]
        prime_sum = sum(i for i in divisors if is_prime(i))
        prime_sums.append(prime_sum)
    return prime_sums

