int is_prime(int num) {
    if (num <= 1) return 0;
    for (int i = 2; i <= sqrt(num); i++) {
        if (num % i == 0) return 0;
    }
    return 1;
}

int sum_of_primes_divisors(int n) {
    int sum = 0;
    for (int i = 1; i <= n; i++) {
        if (n % i == 0 && is_prime(i)) {
            sum += i;
        }
    }
    return sum;
}

int* calculate_sums(int count, int* nums) {
    int* results = (int*)malloc(count * sizeof(int));
    for (int i = 0; i < count; i++) {
        results[i] = sum_of_primes_divisors(nums[i]);
    }
    return results;
}

